 68→        component={SignUpScreen}
 69→        options={{headerShown: false}}
 70→      />
 71→      <AuthStackNav.Screen
 72→        name="ForgotPassword"
 73→        component={ForgotPasswordScreen}
 74→        options={{headerShown: false}}
 75→      />
 76→    </AuthStackNav.Navigator>
 77→  );
