 80→function MainTabNavigator() {
 81→  const {colors} = useTheme();
 82→  const {session} = useAuth();
 83→  const token = session?.access_token ?? '';
 84→  const userId = session?.user.id ?? '';
 85→
 86→  const {data: countData} = useQuery({
 87→    queryKey: ['notification-count', userId],
 88→    enabled: Boolean(token && userId),
 89→    queryFn: () => socialApi.getNotificationsCount(token, userId),
 90→    refetchInterval: 30_000,
 91→  });
 92→  const unreadCount = countData?.count ?? 0;
 93→
 94→  return (
 95→    <MainTabs.Navigator
 96→      screenOptions={{
 97→        headerStyle: {backgroundColor: colors.bgPrimary},
 98→        headerTintColor: colors.textPrimary,
 99→        headerShadowVisible: false,
100→        tabBarStyle: {
101→          backgroundColor: colors.bgCard,
102→          borderTopColor: colors.borderCard,
103→          borderTopWidth: 1,
104→          elevation: 0,
105→        },
106→        tabBarActiveTintColor: colors.accentAmber,
107→        tabBarInactiveTintColor: colors.textMuted,
108→        tabBarLabelStyle: {
109→          fontSize: 11,
110→          fontWeight: '600',
111→        },
112→      }}>
113→      <MainTabs.Screen
114→        name="Home"
115→        component={HomeFeedScreen}
116→        options={{
117→          headerShown: false,
118→          tabBarIcon: ({color, size}) => <HomeIcon size={size} color={color} />,
119→        }}
120→      />
121→      <MainTabs.Screen
122→        name="Explore"
123→        component={ExploreScreen}
124→        options={{
125→          tabBarIcon: ({color, size}) => <CompassIcon size={size} color={color} />,
126→        }}
127→      />
128→      <MainTabs.Screen
129→        name="Stories"
130→        component={StoryBrowserScreen}
131→        options={{
132→          tabBarIcon: ({color, size}) => <BookIcon size={size} color={color} />,
133→        }}
134→      />
135→      <MainTabs.Screen
136→        name="Notifications"
137→        component={NotificationsScreen}
138→        options={{
139→          tabBarIcon: ({color, size}) => <BellIcon size={size} color={color} />,
140→          tabBarBadge: unreadCount > 0 ? unreadCount : undefined,
141→          tabBarBadgeStyle: {
142→            backgroundColor: colors.accentAmber,
143→            color: '#1A1612',
144→            fontSize: 11,
145→            fontWeight: '700',
146→          },
147→        }}
148→      />
149→      <MainTabs.Screen
150→        name="Profile"
151→        component={ProfileScreen}
152→        options={{
153→          tabBarIcon: ({color, size}) => <UserIcon size={size} color={color} />,
154→        }}
155→      />
156→    </MainTabs.Navigator>
157→  );
158→}
