195→export function RootNavigator() {
196→  const {loading, session} = useAuth();
197→  const {colors, isDark} = useTheme();
198→
199→  const navTheme = useMemo(
200→    () => ({
201→      ...(isDark ? DarkTheme : DefaultTheme),
