203→        ...(isDark ? DarkTheme.colors : DefaultTheme.colors),
204→        background: colors.bgPrimary,
205→        card: colors.bgElevated,
206→        border: colors.borderLight,
207→        text: colors.textPrimary,
208→        primary: colors.accentAmber,
209→        notification: colors.accentAmber,
210→      },
211→    }),
212→    [colors, isDark],
213→  );
214→
215→  if (loading) {
216→    return (
217→      <View style={[styles.loadingContainer, {backgroundColor: colors.bgPrimary}]}>
218→        <ActivityIndicator color={colors.loaderColor} />
219→        <Text style={[styles.loadingText, {color: colors.textMuted}]}>
220→          Loading session...
221→        </Text>
222→      </View>
223→    );
224→  }
