226→  return (
227→    <NavigationContainer theme={navTheme}>
228→      <RootStack.Navigator
229→        screenOptions={{
230→          headerStyle: {backgroundColor: colors.bgElevated},
231→          headerTintColor: colors.textPrimary,
232→          headerShadowVisible: false,
233→          contentStyle: {backgroundColor: colors.bgPrimary},
234→        }}>
235→        {!session ? (
236→          <RootStack.Screen
237→            name="Auth"
238→            component={AuthNavigator}
239→            options={{headerShown: false}}
240→          />
241→        ) : (
242→          <>
243→            <RootStack.Screen
244→              name="Main"
245→              options={{headerShown: false}}>
246→              {() => (
247→                <LoggedInShell>
248→                  <MainTabNavigator />
249→                </LoggedInShell>
250→              )}
251→            </RootStack.Screen>
252→            <RootStack.Screen
253→              name="PostDetail"
254→              component={PostDetailScreen}
255→              options={{title: 'Post'}}
256→            />
257→            <RootStack.Screen
258→              name="JournalEditor"
259→              component={JournalEditorScreen}
260→              options={{title: 'Journal Editor'}}
261→            />
262→            <RootStack.Screen
263→              name="StoryDetail"
264→              component={StoryDetailScreen}
265→              options={{title: 'Story'}}
266→            />
267→            <RootStack.Screen
268→              name="StoryEditor"
269→              component={StoryEditorScreen}
270→              options={{title: 'Story Editor'}}
271→            />
272→            <RootStack.Screen
273→              name="StoryDashboard"
274→              component={StoryDashboardScreen}
275→              options={{title: 'My Stories'}}
276→            />
277→            <RootStack.Screen
278→              name="StoryLibrary"
279→              component={StoryLibraryScreen}
280→              options={{title: 'Story Library'}}
281→            />
282→            <RootStack.Screen
283→              name="StoryChapterManager"
284→              component={StoryChapterManagerScreen}
285→              options={{title: 'Chapter Manager'}}
286→            />
287→            <RootStack.Screen
288→              name="StoryChapterEditor"
289→              component={StoryChapterEditorScreen}
290→              options={{title: 'Chapter Editor'}}
291→            />
292→            <RootStack.Screen
293→              name="StoryChapterReader"
294→              component={StoryChapterReaderScreen}
295→              options={{title: 'Chapter'}}
296→            />
297→            <RootStack.Screen
298→              name="VisitProfile"
299→              component={VisitProfileScreen}
300→              options={{title: 'Profile'}}
301→            />
302→            <RootStack.Screen
