 98→export const mobileApi = {
 99→  async getJournals(cursor: string | null, limit = 10, userId?: string): Promise<CursorPage<JournalItem>> {
100→    const params = new URLSearchParams();
101→    params.set('limit', String(limit));
102→    if (cursor) {
103→      params.set('before', cursor);
104→    }
105→    if (userId) {
106→      params.set('userId', userId);
107→    }
108→
109→    return apiRequest<CursorPage<JournalItem>>(`/journals?${params.toString()}`, {
110→      method: 'GET',
111→    });
112→  },
113→
114→  async getJournalById(journalId: string, userId?: string): Promise<{ journal: JournalItem }> {
115→    const params = new URLSearchParams();
116→    if (userId) {
117→      params.set('userId', userId);
118→    }
119→
120→    const suffix = params.toString() ? `?${params.toString()}` : '';
121→    return apiRequest<{ journal: JournalItem }>(`/journal/${encodeURIComponent(journalId)}${suffix}`, {
122→      method: 'GET',
123→    });
124→  },
125→
126→  async searchUsers(query: string, limit = 20): Promise<{ data: UserPreview[]; hasMore: boolean }> {
127→    const params = new URLSearchParams();
128→    params.set('query', query.trim());
129→    params.set('limit', String(limit));
130→
131→    return apiRequest<{ data: UserPreview[]; hasMore: boolean }>(`/users/search?${params.toString()}`, {
132→      method: 'GET',
133→    });
134→  },
135→
136→  async searchJournals(query: string, limit = 20, userId?: string): Promise<{ data: JournalItem[]; hasMore: boolean }> {
137→    const params = new URLSearchParams();
138→    params.set('query', query.trim());
139→    params.set('limit', String(limit));
140→    if (userId) {
141→      params.set('userId', userId);
142→    }
143→
144→    return apiRequest<{ data: JournalItem[]; hasMore: boolean }>(`/journals/search?${params.toString()}`, {
145→      method: 'GET',
146→    });
147→  },
148→
149→  async getNotifications(token: string, cursor: string | null, limit = 20): Promise<CursorPage<NotificationItem>> {
150→    const params = new URLSearchParams();
151→    params.set('limit', String(limit));
152→    if (cursor) {
153→      params.set('before', cursor);
154→    }
155→
156→    return apiRequest<CursorPage<NotificationItem>>(`/getNotifications?${params.toString()}`, {
157→      method: 'GET',
