159→        ...authHeaders(token),
160→      },
161→    });
162→  },
163→
164→  async getStreak(userId: string): Promise<StreakResponse> {
165→    return apiRequest<StreakResponse>(`/streak/${encodeURIComponent(userId)}`, {
166→      method: 'GET',
167→    });
168→  },
169→
170→  async getUserData(userId: string): Promise<UserDataResponse> {
171→    const params = new URLSearchParams();
172→    params.set('userId', userId);
173→
174→    return apiRequest<UserDataResponse>(`/getUserData?${params.toString()}`, {
175→      method: 'GET',
176→    });
177→  },
178→
179→  async getUserByUsername(username: string): Promise<UserDataResponse> {
180→    return apiRequest<UserDataResponse>(
181→      `/user/${encodeURIComponent(username)}`,
182→      {method: 'GET'},
183→    );
184→  },
185→
186→  async getHottestMonthly(limit = 5, userId?: string): Promise<CursorPage<JournalItem>> {
187→    const params = new URLSearchParams();
188→    params.set('limit', String(limit));
189→    if (userId) {
190→      params.set('userId', userId);
191→    }
192→
193→    return apiRequest<CursorPage<JournalItem>>(`/journals/hottest-monthly?${params.toString()}`, {
194→      method: 'GET',
