200→      `/journal/${encodeURIComponent(journalId)}/related`,
201→      {method: 'GET'},
202→    );
203→  },
204→
205→  async getUserJournals(token: string, userId: string, cursor: string | null, limit = 10): Promise<CursorPage<JournalItem>> {
206→    const params = new URLSearchParams();
207→    params.set('limit', String(limit));
208→    params.set('userId', userId);
209→    if (cursor) params.set('before', cursor);
210→    return apiRequest<CursorPage<JournalItem>>(`/userJournals?${params.toString()}`, {
211→      method: 'GET',
212→      headers: {Authorization: `Bearer ${token}`},
213→    });
214→  },
215→
216→  async saveJournal(token: string, payload: { title: string; plainText: string; html?: string }): Promise<{ message?: string }> {
217→    const formData = new FormData();
218→
219→    const lexicalPayload = {
220→      root: {
221→        children: [
222→          {
223→            type: 'paragraph',
224→            children: [
225→              {
226→                type: 'text',
227→                text: payload.plainText,
228→                detail: 0,
229→                format: 0,
230→                mode: 'normal',
231→                style: '',
232→                version: 1,
233→              },
234→            ],
235→            direction: null,
236→            format: '',
237→            indent: 0,
238→            version: 1,
239→          },
240→        ],
241→        direction: null,
242→        format: '',
243→        indent: 0,
244→        type: 'root',
245→        version: 1,
246→      },
247→    };
248→
249→    formData.append('title', payload.title);
250→    formData.append('content', JSON.stringify(lexicalPayload));
251→    formData.append('post_type', 'text');
252→
253→    return apiRequest<{ message?: string }>('/save-journal', {
254→      method: 'POST',
255→      headers: {
256→        ...authHeaders(token),
257→      },
258→      body: formData,
259→      timeoutMs: 30000,
260→      retries: 0,
261→    });
262→  },
263→};
