 63→
 64→  async getComments(
 65→    postId: string,
 66→    cursor: string | null = null,
 67→    limit = 20,
 68→  ): Promise<{comments: JournalComment[]; hasMore?: boolean}> {
 69→    const params = new URLSearchParams();
 70→    params.set('postId', postId);
 71→    params.set('limit', String(limit));
 72→    if (cursor) {
 73→      params.set('before', cursor);
 74→    }
 75→
 76→    return apiRequest<{comments: JournalComment[]; hasMore?: boolean}>(
 77→      `/getComments?${params.toString()}`,
 78→      {method: 'GET'},
 79→    );
 80→  },
 81→
 82→  async getReplies(
 83→    postId: string,
 84→    parentId: string,
 85→    limit = 20,
 86→  ): Promise<{comments: JournalComment[]; hasMore?: boolean}> {
 87→    const params = new URLSearchParams();
 88→    params.set('postId', postId);
 89→    params.set('parentId', parentId);
